import { isValidEmail, isValidUrl } from '../validators';

describe('isValidEmail', () => {
  const validEmails = [
    'user@example.com',
    'user.name@domain.org',
    'user+tag@example.co.uk',
    'a@b.c',
  ];

  const invalidEmails = [
    '',
    'no-at-sign',
    '@missing-local.com',
    'missing-domain@',
    'user @space.com',
    'user@.com',
  ];

  test.each(validEmails)('accepts valid email: %s', (email) => {
    expect(isValidEmail(email)).toBe(true);
  });

  test.each(invalidEmails)('rejects invalid email: %s', (email) => {
    expect(isValidEmail(email)).toBe(false);
  });
});

describe('isValidUrl', () => {
  const validUrls = [
    'https://example.com',
    'http://localhost:3000',
    'https://example.com/path?q=1',
    'https://sub.domain.example.com',
  ];

  const invalidUrls = [
    '',
    'not a url',
    'ftp://example.com',
    'example.com',
    '://missing-protocol',
  ];

  test.each(validUrls)('accepts valid URL: %s', (url) => {
    expect(isValidUrl(url)).toBe(true);
  });

  test.each(invalidUrls)('rejects invalid URL: %s', (url) => {
    expect(isValidUrl(url)).toBe(false);
  });
});
